class Solution {
    public int[] gardenNoAdj(int n, int[][] paths) {
        List<Integer>[] g = new ArrayList[n + 1];
        for (int i = 1; i <= n; i++) g[i] = new ArrayList<>();
        for (int[] p : paths) {
            int a = p[0], b = p[1];
            g[a].add(b);
            g[b].add(a);
        }
        int[] ans = new int[n];
        for (int i = 1; i <= n; i++) {
            boolean[] used = new boolean[5];
            for (int nb : g[i]) {
                if (ans[nb - 1] != 0) used[ans[nb - 1]] = true;
            }
            for (int c = 1; c <= 4; c++) {
                if (!used[c]) {
                    ans[i - 1] = c;
                    break;
                }
            }
        }
        return ans;
    }
}
